import "mylib";
// The augmenting interface's heritage clause references `Extra` unqualified.
// It must resolve against the augmented module `mylib`'s own exports — tsc
// shares the module's symbol table inside a `declare module` augmentation.
// Without that resolution the base drops and `Base` never gains `Extra`'s
// members through the augmentation.
declare module "mylib" {
  interface Base extends Extra {
    plus: boolean;
  }
}
